#include<bits/stdc++.h>
using namespace std;
bool vis[410],flag[410][410];
int match[410];
int n,m,t;
bool km(int x)
{
    for(int i=1;i<=m;i++)
    {
        if(!vis[i]&&!flag[x][i])
        {
            vis[i]=1;
            if(match[i]==0||km(match[i]))
            {
                match[i]=x;
                return true;
            }
        }
    }
    return false;
}
int main()
{
    scanf("%d%d%d",&n,&m,&t);
    for(int i=1;i<=t;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        flag[x][y]=1;
    }
    int ans=0;
    for(int i=1;i<=n;i++)
    {
        memset(vis,0,sizeof(vis));
        ans+=km(i);
    }
    printf("%d",ans);
    return 0;
}
